def rle_encode(s):
    result = []
    i = 0
    while i < len(s):
        j = i
        while j < len(s) and s[j] == s[i]:
            j += 1
        result.append(f"{s[i]}{j - i}")
        i = j
    return ''.join(result)

def rle_decode(s):
    result = []
    i = 0
    while i < len(s):
        ch = s[i]
        i += 1
        num = ''
        while i < len(s) and s[i].isdigit():
            num += s[i]
            i += 1
        result.append(ch * int(num))
    return ''.join(result)

for text in ["AAADDBOOOO", "NOOOOOOOOOO", "YEEEEEAH", "HURRAY"]:
    encoded = rle_encode(text)
    decoded = rle_decode(encoded)
    ratio = len(text) / len(encoded)
    print(f"{text} ({len(text)}byte) -> {encoded} ({len(encoded)}byte), 압축비={ratio:.2f}, 복원 성공={decoded == text}")
